// Search by code prefix or display text (case-insensitive)
export function searchICD9(query: string, limit = 10): ICD9Entry[] {
  if (!query || query.length < 2) return [];
  const q = query.toLowerCase();
  const results: ICD9Entry[] = [];
  for (const entry of ICD9_DATA) {
    if (entry.code.toLowerCase().startsWith(q) || entry.display.toLowerCase().includes(q)) {
      results.push(entry);
      if (results.length >= limit) break;
    }
  }
  return results;
}

export function getICD9ByCode(code: string): ICD9Entry | undefined {
  return ICD9_DATA.find(e => e.code === code);
}

export const ICD9_CATEGORIES = [...new Set(ICD9_DATA.map(e => e.category))];
